var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","JPN":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 対象者観察","ENG":"CCN No. CSM002M000755-09\\n<color=#ffd34c>Class 3 Priority</color> File Access Approved\\nAppendix: Subject Surveillance","TWN":"(TWN)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"████\xA0대행.\xA0관찰대상\xA0라이언 페리어에 관한\xA0사안으로 연락드렸습니다.","JPN":"████ 代行。観察対象ライアン・フェリエーに関する事案でご連絡致しました。","ENG":"████ Executive. Contacting you regarding the surveillance subject Ryan Ferrier.","TWN":"(TWN)████\xA0대행.\xA0관찰대상\xA0라이언 페리어에 관한\xA0사안으로 연락드렸습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그렇잖아도 슬슬 연락이 올 때라고 생각했지.","JPN":"ただでさえそろそろ連絡が来る時と思ったの。","ENG":"Figured you'd reach out sooner or later.","TWN":"(TWN)그렇잖아도 슬슬 연락이 올 때라고 생각했지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"전송해 준 자료는 잘 확인했네.\\n렌즈 돌아가는 소리를 듣다니 어떻게 된 인간인가?","JPN":"転送してくれた資料はよく確認したな。\\nレンズ帰る話を聞くなんてどうなった人間であるか?","ENG":"I've reviewed the materials you transmitted.\\nWhat kind of man hears the sound of lenses spinning?","TWN":"(TWN)전송해 준 자료는 잘 확인했네.\\n렌즈 돌아가는 소리를 듣다니 어떻게 된 인간인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"성격이 매우 까탈스럽거나 현 관리국의 인증 과정이 부실했다거나, 둘 중 하나겠죠.","JPN":"性格が非常に気難しいとか現管理局の認証過程が不実だったとか、二つ中一つでしょう。","ENG":"Either his personality is extremely abrasive, or the current administration's vetting process was inadequate. It must be one or the other.","TWN":"(TWN)성격이 매우 까탈스럽거나 현 관리국의 인증 과정이 부실했다거나, 둘 중 하나겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"둘 다일 수도 있겠지.","JPN":"両方ともである場合もあるだろう。","ENG":"Could be both.","TWN":"(TWN)둘 다일 수도 있겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아무튼,\xA0조사는 잘 되고 있나?\xA0","JPN":"とにかく、調査はよくなっているか?","ENG":"Anyway, is the investigation proceeding smoothly?","TWN":"(TWN)아무튼,\xA0조사는 잘 되고 있나?\xA0"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"순조롭게 진행 중이죠.\\n금번 보고 사항은 관찰대상의 이력입니다.","JPN":"順調に進行中ですよ。\\n今度報告事項は観察対象の履歴です。","ENG":"Proceeding without issue.\\nThis report concerns the surveillance subject's history.","TWN":"(TWN)순조롭게 진행 중이죠.\\n금번 보고 사항은 관찰대상의 이력입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흐음......\xA0기존 정보에서 큰 변동이 있었나?","JPN":"フウム......既存情報で大きい変動があったか?","ENG":"Hmm...... Were there any significant discrepancies with existing records?","TWN":"(TWN)흐음......\xA0기존 정보에서 큰 변동이 있었나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지금까지 밝혀진 사실은 과거 SAS 대원으로 복무했다는 것뿐입니다.","JPN":"今まで明かされた事実は過去SAS隊員で服務したということだけです。","ENG":"Thus far, the only confirmed fact is that he served as an SAS operative in the past.","TWN":"(TWN)지금까지 밝혀진 사실은 과거 SAS 대원으로 복무했다는 것뿐입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"기관에 들어간 경위는 현재 조사 중입니다.","JPN":"機関に入った経緯は現在調査中です。","ENG":"The circumstances of his entry into the organization are currently under investigation.","TWN":"(TWN)기관에 들어간 경위는 현재 조사 중입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"군인 신분이었다면 차출되었을 수도 있지 않겠나?","JPN":"軍人身分だったら差出されることができたかも知れなくないか?","ENG":"Being a military man, one would think he'd have been discharged?","TWN":"(TWN)군인 신분이었다면 차출되었을 수도 있지 않겠나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"프리드웬 기관은 왕실 산하 기관이기 때문에 군과 직접적인 관련은 없습니다.","JPN":"プリドウェン機関は王室傘下機関だから軍と直接的な関連はないです。","ENG":"The Friedwen Agency is a strictly civilian alpine agency, so there is no direct connection to the military.","TWN":"(TWN)프리드웬 기관은 왕실 산하 기관이기 때문에 군과 직접적인 관련은 없습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"굳이 연관을 짓는다면 성격이 어느 정도 겹치는 정보부와 연대한 사례가 있긴 하죠.","JPN":"敢えて関連を作ったら性格がどれくらい重なる情報部と連帯した事例があったりします。","ENG":"If we must force a connection, there was a case of him cooperating with Intelligence, whose temperament overlaps with his to some degree.","TWN":"(TWN)굳이 연관을 짓는다면 성격이 어느 정도 겹치는 정보부와 연대한 사례가 있긴 하죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"공문서를 조사해 봤지만 공식적인 전출 명령은 없던 것으로 나타났습니다.","JPN":"公文書を調査してみたが公式的な転出命令はなかったことと明らかになりました。","ENG":"We investigated official documents, but no formal transfer orders were found.","TWN":"(TWN)공문서를 조사해 봤지만 공식적인 전출 명령은 없던 것으로 나타났습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"군 기록 상에는 대환류 종결 직후 중사로 전역한 것이 마지막입니다.","JPN":"軍記録上には大患類終決直後中佐で戦域したことが終わりです。","ENG":"Military records indicate his final entry was a transfer to the reserves following the conclusion of a major exchange.","TWN":"(TWN)군 기록 상에는 대환류 종결 직후 중사로 전역한 것이 마지막입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"군에 복무할 당시의 평가는 어땠나?","JPN":"軍に服務する当時の評価はどうだったか?","ENG":"What was his evaluation during his military service?","TWN":"(TWN)군에 복무할 당시의 평가는 어땠나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신원 보호가 철저해서 많은 인원을 인터뷰하기는 어려웠습니다.","JPN":"身元保護が徹底的で多くの人員をインタビューすることは難しかったです。","ENG":"Source protection is strict, making it difficult to interview many personnel.","TWN":"(TWN)신원 보호가 철저해서 많은 인원을 인터뷰하기는 어려웠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 공통적으로 복무 당시에는 활달한 사람이었다고 합니다.\\n평시에는 팀의 무드 메이커 역할을 했다더군요.","JPN":"しかし共通的に服務当時には活達な人だったとします。\\n平時にはチームのムードメーカー役割をしたと言う。","ENG":"However, the consensus is that he was an active individual during service.\\nApparently he served as the team's mood maker during peacetime.","TWN":"(TWN)하지만 공통적으로 복무 당시에는 활달한 사람이었다고 합니다.\\n평시에는 팀의 무드 메이커 역할을 했다더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"군인으로서의 능력도 우수했고, 특히 인터뷰에 응한 이들 모두 격투술이 굉장히 뛰어난 사람으로 기억했습니다.","JPN":"軍人としての能力も優秀で、特にインタビューに応じたこれら皆格闘術がものすごく優れている人で記憶しました。","ENG":"His abilities as a soldier were also excellent, remembered particularly as someone with outstanding combat skills among those who responded to the interview.","TWN":"(TWN)군인으로서의 능력도 우수했고, 특히 인터뷰에 응한 이들 모두 격투술이 굉장히 뛰어난 사람으로 기억했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"타 부대 혹은 경찰 측에 파견되어 교관으로 활동하기도 했다더군요.","JPN":"他部隊あるいは警察側に派遣されて教官で活動したりしたと言う。","ENG":"It was also said that he was seconded to other units or police agencies and served as an instructor.","TWN":"(TWN)타 부대 혹은 경찰 측에 파견되어 교관으로 활동하기도 했다더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"군인으로서는 흠잡을 데 없었단 뜻인데.... 왜 굳이 프리드웬에 갔을까.","JPN":"軍人としては粗を探すところなかったという意味だが....なぜ敢えてプリドウェンに行っただろうか。","ENG":"Meaning he was flawless as a soldier.... Why did he bother going to Friedwen?","TWN":"(TWN)군인으로서는 흠잡을 데 없었단 뜻인데.... 왜 굳이 프리드웬에 갔을까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"활동한 시기로 보면 군에서도 대 침식전을 염두에 둘 시기이네만.","JPN":"活動した時期に見れば軍でも台侵食前を念頭に二つ酸っぱいだねだけ。","ENG":"Given the period of his activities, he would have been in line for a major promotion in the military.","TWN":"(TWN)활동한 시기로 보면 군에서도 대 침식전을 염두에 둘 시기이네만."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"인터뷰에서 단서가 있었습니다만, 확인에 다소 시일이 필요할 겁입니다.","JPN":"インタビューで手がかりがあったのですが、確認にちょっとシールが必要な恐怖心です。","ENG":"There was a clue in the interview, but verification will require some time.","TWN":"(TWN)인터뷰에서 단서가 있었습니다만, 확인에 다소 시일이 필요할 겁입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좋아. 일단 동향은 계속 관찰하고 있게.\\n카메라 사용만 자제하고.","JPN":"良い。一旦動向はずっと観察していなさい。\\nカメラ使用だけ慎んで。","ENG":"Understood. Continue monitoring the trends for now.\\nJust refrain from using cameras.","TWN":"(TWN)좋아. 일단 동향은 계속 관찰하고 있게.\\n카메라 사용만 자제하고."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네.\xA02차 조사 내용을\xA0DB에 등록해 두겠습니다.\\n추후 확인 부탁드립니다.","JPN":"はい。２次調査内容をDBに登録しておきます。\\n追後確認お願いします。","ENG":"Yes. I will log the secondary investigation contents to the DB.\\nPlease review at your earliest convenience.","TWN":"(TWN)네.\xA02차 조사 내용을\xA0DB에 등록해 두겠습니다.\\n추후 확인 부탁드립니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};